import java.util.Scanner;class StackLinkedList{// Node classclass Node{int data;Node next;Node(int value){data = value;next = null;}}Node top = null;// Push operationvoid push(int value){Node newNode = new Node(value);newNode.next = top;top = newNode;System.out.println(value + " pushed into stack.");}// Pop operationvoid pop(){if(top == null){System.out.println("Stack Underflow!");}
else{System.out.println(top.data + " popped from stack.");top = top.next;}}// Peek operationvoid peek(){if(top == null){System.out.println("Stack is empty.");}else{System.out.println("Top element is: " + top.data);}}do{System.out.println("\n--- STACK USING LINKED LIST ---");System.out.println("1. Push");System.out.println("2. Pop");System.out.println("3. Peek");System.out.println("4. Display");System.out.println("5. Exit");System.out.print("Enter your choice: ");choice = sc.nextInt();switch(choice){case 1:System.out.print("Enter value: ");value = sc.nextInt();s.push(value);break;case 2:                    s.pop();                    break;                case 3:                    s.peek();                    break;                case 4:                    s.display();                    break;                case 5:                    System.out.println("Exiting program...");                    break;                default:                    System.out.println("Invalid choice!");            }        } while(choice != 5);        sc.close();    }}
